import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';
import AnimatedNumber from '../../components/AnimatedNumber';

const COLORS = ['#1a56db','#10b981','#f59e0b','#ef4444','#6366f1','#06b6d4','#ec4899','#8b5cf6'];

const roleBadge = { admin:'badge-red', hod:'badge-yellow', faculty:'badge-purple', student:'badge-blue' };

function DetailModal({ title, icon, onClose, children }) {
  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ maxWidth: 680 }}>
        <div className="modal-header">
          <span className="modal-title">{icon} {title}</span>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        <div style={{ maxHeight: '65vh', overflowY: 'auto' }}>
          {children}
        </div>
      </div>
    </div>
  );
}

export default function AdminDashboard() {
  const [data,    setData]    = useState(null);
  const [loading, setLoading] = useState(true);
  const [modal,   setModal]   = useState(null); // { type, title, icon }
  const [users,   setUsers]   = useState([]);
  const [loadingUsers, setLoadingUsers] = useState(false);

  useEffect(() => {
    axios.get('/api/admin/stats')
      .then(res => { setData(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const openModal = async (type, title, icon) => {
    setModal({ type, title, icon });
    setUsers([]);
    setLoadingUsers(true);
    try {
      let url = '/api/admin/users';
      let params = {};
      if (type === 'students')    params.role = 'student';
      else if (type === 'faculty') params.role = 'faculty';
      else if (type === 'hods')    params.role = 'hod';
      else if (type === 'all')     params = {};

      const res = await axios.get(url, { params });
      setUsers(res.data.users.filter(u => u.isActive));
    } catch { setUsers([]); }
    finally { setLoadingUsers(false); }
  };

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;
  if (!data)   return <div className="empty-state"><div className="empty-icon">⚠️</div><div className="empty-text">Failed to load</div></div>;

  const { stats, studentsByDept, studentsBySem } = data;
  const semData  = studentsBySem.map(s => ({ name: `Sem ${s._id}`, students: s.count }));
  const deptData = studentsByDept.map(d => ({ name: d.deptName || 'Unknown', value: d.count }));

  const statCards = [
    { key: 'students',  value: stats.totalStudents,    label: 'Total Students',   icon: '👨‍🎓', color: 'blue',   modalTitle: 'All Students'      },
    { key: 'faculty',   value: stats.totalFaculty,     label: 'Faculty Members',  icon: '👩‍🏫', color: 'green',  modalTitle: 'All Faculty'        },
    { key: 'hods',      value: stats.totalHods,        label: 'HODs',             icon: '🧑‍💼', color: 'purple', modalTitle: 'All HODs'           },
    { key: 'depts',     value: stats.totalDepartments, label: 'Departments',      icon: '🏢', color: 'yellow',  modalTitle: null                 },
    { key: 'subjects',  value: stats.totalSubjects,    label: 'Subjects',         icon: '📚', color: 'cyan',    modalTitle: null                 },
    { key: 'marks',     value: stats.totalMarksEntries,label: 'Marks Entries',    icon: '📊', color: 'red',     modalTitle: null                 },
  ];

  return (
    <div>
      <div className="stats-grid">
        {statCards.map(card => (
          <div
            key={card.key}
            className={`stat-card ${card.color}`}
            onClick={() => card.modalTitle && openModal(card.key, card.modalTitle, card.icon)}
            style={{ cursor: card.modalTitle ? 'pointer' : 'default', userSelect: 'none' }}
            title={card.modalTitle ? `Click to view ${card.modalTitle}` : ''}
          >
            <div className="stat-icon">{card.icon}</div>
            <div>
              <div className="stat-value"><AnimatedNumber value={card.value} /></div>
              <div className="stat-label">{card.label}</div>
              {card.modalTitle && (
                <div style={{ fontSize: 10, color: 'var(--primary)', marginTop: 2, fontWeight: 600 }}>
                  Click to view →
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Charts */}
      <div className="charts-grid">
        <div className="card">
          <div className="card-header"><span className="card-title">📊 Students by Semester</span></div>
          <div className="card-body">
            {semData.length ? (
              <div className="chart-container">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={semData} margin={{ top:5, right:10, left:-10, bottom:5 }}>
                    <XAxis dataKey="name" tick={{ fontSize:11 }} />
                    <YAxis allowDecimals={false} tick={{ fontSize:11 }} />
                    <Tooltip />
                    <Bar dataKey="students" fill="#1a56db" radius={[4,4,0,0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            ) : <div className="empty-state"><div className="empty-text">No student data</div></div>}
          </div>
        </div>

        <div className="card">
          <div className="card-header"><span className="card-title">🏢 Students by Department</span></div>
          <div className="card-body">
            {deptData.length ? (
              <div className="chart-container">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart margin={{ top:5, right:5, left:5, bottom:5 }}>
                    <Pie data={deptData} cx="50%" cy="45%" outerRadius="60%"
                      dataKey="value" label={({ name, value }) => `${value}`} labelLine>
                      {deptData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                    </Pie>
                    <Tooltip />
                    <Legend layout="horizontal" verticalAlign="bottom" align="center" wrapperStyle={{ fontSize:11, paddingTop:8 }} />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            ) : <div className="empty-state"><div className="empty-text">No department data</div></div>}
          </div>
        </div>
      </div>

      {/* Detail Modal */}
      {modal && (
        <DetailModal title={modal.title} icon={modal.icon} onClose={() => setModal(null)}>
          {loadingUsers ? (
            <div className="empty-state" style={{ padding: 40 }}>
              <div className="spinner" style={{ margin: '0 auto' }}></div>
            </div>
          ) : users.length === 0 ? (
            <div className="empty-state"><div className="empty-icon">👥</div><div className="empty-text">No users found</div></div>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>#</th><th>Name</th><th>Roll Number</th><th>Role</th><th>Department</th>
                  {modal.type === 'students' && <><th>Sem</th><th>Section</th></>}
                </tr>
              </thead>
              <tbody>
                {users.map((u, i) => (
                  <tr key={u._id}>
                    <td>{i + 1}</td>
                    <td className="fw-600">{u.name}</td>
                    <td style={{ fontFamily: 'monospace', fontSize: 12 }}>{u.rollNumber}</td>
                    <td><span className={`badge ${roleBadge[u.role] || 'badge-gray'}`}>{u.role}</span></td>
                    <td>{u.department?.name || '—'}</td>
                    {modal.type === 'students' && (
                      <>
                        <td>{u.semester || '—'}</td>
                        <td>{u.section || '—'}</td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          )}
          <div style={{ padding: '12px 20px', borderTop: '1px solid var(--border)', fontSize: 13, color: 'var(--text-muted)' }}>
            Total: <strong>{users.length}</strong> {modal.type}
          </div>
        </DetailModal>
      )}
    </div>
  );
}
